exercises.solution_code:
#include <iostream>

int main()
{
    char ch {};
    std::cin >> ch;

    std::cout << "ASCII: " << static_cast<int>(ch) << '\n';

    if (ch >= 'A' && ch <= 'Z')
        std::cout << "uppercase\n";
    else if (ch >= 'a' && ch <= 'z')
        std::cout << "lowercase\n";
    else if (ch >= '0' && ch <= '9')
        std::cout << "digit\n";
    else
        std::cout << "other\n";

    return 0;
}

