exercises.solution_code:
#include <iostream>

int main()
{
    int offset {};
    std::cin >> offset;

    char ch1 {};
    std::cin >> ch1;
    int new_ascii1 { static_cast<int>(ch1) + offset };
    char new_ch1   { static_cast<char>(new_ascii1) };
    std::cout << ch1 << " (" << static_cast<int>(ch1) << ") -> " << new_ch1 << " (" << new_ascii1 << ")\n";

    char ch2 {};
    std::cin >> ch2;
    int new_ascii2 { static_cast<int>(ch2) + offset };
    char new_ch2   { static_cast<char>(new_ascii2) };
    std::cout << ch2 << " (" << static_cast<int>(ch2) << ") -> " << new_ch2 << " (" << new_ascii2 << ")\n";

    char ch3 {};
    std::cin >> ch3;
    int new_ascii3 { static_cast<int>(ch3) + offset };
    char new_ch3   { static_cast<char>(new_ascii3) };
    std::cout << ch3 << " (" << static_cast<int>(ch3) << ") -> " << new_ch3 << " (" << new_ascii3 << ")\n";

    return 0;
}
